import type { QuizQuestion } from './quizzes'

export const quizzes3: Record<number, QuizQuestion[]> = {
  22: [
    { id: 'q22_1', question: 'Quel type de NAT associe une adresse IP privee a une adresse IP publique de maniere permanente et fixe ?', options: ['NAT dynamique', 'PAT (Port Address Translation)', 'NAT statique', 'NAT overload'], correct: 2, explanation: 'Le NAT statique cree un mappage permanent un-a-un entre une adresse privee (inside local) et une adresse publique (inside global). Il est utilise pour les serveurs internes devant etre accessibles depuis Internet (serveur web, mail). La commande est : ip nat inside source static [ip-privee] [ip-publique].' },
    { id: 'q22_2', question: 'Quelle commande configure une interface comme cote interne (prive) pour le NAT sur un routeur Cisco ?', options: ['ip nat outside', 'ip nat inside', 'ip nat pool', 'ip nat enable'], correct: 1, explanation: 'La commande "ip nat inside" est appliquee sur l\'interface connectee au reseau prive (LAN). L\'interface connectee a Internet recoit "ip nat outside". Ces deux commandes sont obligatoires pour que le NAT fonctionne. Le routeur traduit les adresses des paquets transitant entre les interfaces inside et outside.' },
    { id: 'q22_3', question: 'Dans la terminologie NAT, que represente l\'adresse "inside global" ?', options: ['L\'adresse privee de l\'hote interne vue depuis le LAN', 'L\'adresse publique attribuee a l\'hote interne vue depuis Internet', 'L\'adresse publique de l\'hote distant sur Internet', 'L\'adresse privee de l\'hote distant'], correct: 1, explanation: 'Inside global est l\'adresse IP publique qui represente un hote interne vu depuis le reseau externe (Internet). Inside local est l\'adresse privee reelle de l\'hote. Outside global est l\'adresse publique de l\'hote distant. Outside local est l\'adresse par laquelle l\'hote distant est connu en interne (souvent identique a outside global).' },
    { id: 'q22_4', question: 'Combien d\'hotes internes peuvent partager une seule adresse IP publique grace au PAT ?', options: ['Un seul hote', 'Jusqu\'a 255 hotes', 'Jusqu\'a environ 65 000 hotes (grace aux numeros de port)', 'Exactement 1024 hotes'], correct: 2, explanation: 'Le PAT (Port Address Translation), aussi appele NAT overload, utilise les numeros de port source (theoriquement 65 535 par adresse IP) pour distinguer les sessions de differents hotes internes. En pratique, des milliers d\'hotes peuvent partager une seule IP publique. C\'est la forme de NAT la plus utilisee (foyers, entreprises).' },
    { id: 'q22_5', question: 'Quelle commande affiche la table de traduction NAT active sur un routeur Cisco ?', options: ['show ip nat pools', 'show ip nat translations', 'show ip nat statistics', 'show running-config | include nat'], correct: 1, explanation: 'La commande "show ip nat translations" affiche toutes les traductions NAT actives avec les adresses inside local, inside global, outside local et outside global. "show ip nat statistics" affiche les compteurs (nombre de traductions actives, hits, misses). "clear ip nat translation *" vide la table.' },
    { id: 'q22_6', question: 'Quel est le principal probleme resolu par le NAT ?', options: ['La latence du reseau', 'La penure d\'adresses IPv4 publiques', 'La securite du Wi-Fi', 'La resolution DNS'], correct: 1, explanation: 'Le NAT a ete cree principalement pour pallier la penure d\'adresses IPv4 publiques (4,3 milliards seulement). Il permet a de nombreux hotes utilisant des adresses privees (RFC 1918) de partager un nombre limite d\'adresses publiques. Le NAT offre aussi un effet de securite en masquant la topologie interne.' },
    { id: 'q22_7', question: 'Quelle est la difference entre NAT dynamique et PAT ?', options: ['Le NAT dynamique est plus rapide', 'Le NAT dynamique associe une adresse publique par hote (un-a-un), le PAT partage une adresse publique entre plusieurs hotes via les ports', 'Le PAT ne fonctionne qu\'avec IPv6', 'Il n\'y a aucune difference'], correct: 1, explanation: 'Le NAT dynamique puise dans un pool d\'adresses publiques et attribue une adresse par hote (mappage un-a-un temporaire). Si le pool est epuise, les hotes supplementaires ne peuvent pas sortir. Le PAT (overload) partage une ou plusieurs adresses publiques entre tous les hotes en utilisant des numeros de port uniques pour chaque session.' },
    { id: 'q22_8', question: 'Quelle commande configure un pool d\'adresses publiques pour le NAT dynamique ?', options: ['ip nat inside source list 1 pool MONPOOL', 'ip nat pool MONPOOL 203.0.113.1 203.0.113.10 netmask 255.255.255.0', 'ip nat outside source static 203.0.113.1', 'access-list 1 permit 203.0.113.0 0.0.0.255'], correct: 1, explanation: 'La commande "ip nat pool MONPOOL [ip-debut] [ip-fin] netmask [masque]" definit un pool d\'adresses publiques. Ensuite, "ip nat inside source list [ACL] pool MONPOOL" lie une ACL (qui identifie le trafic interne) au pool. Pour le PAT, on ajoute le mot-cle "overload" a la fin de cette derniere commande.' },
    { id: 'q22_9', question: 'Quel mot-cle ajoute-t-on a la commande NAT pour activer le PAT (partage d\'une seule IP publique) ?', options: ['shared', 'overload', 'multiplex', 'pat-enable'], correct: 1, explanation: 'Le mot-cle "overload" active le PAT. Exemple : "ip nat inside source list 1 interface GigabitEthernet0/1 overload" traduit tout le trafic correspondant a l\'ACL 1 en utilisant l\'adresse IP de l\'interface de sortie avec des ports differents. C\'est la configuration la plus courante en entreprise et chez les particuliers.' },
    { id: 'q22_10', question: 'Pourquoi le NAT pose-t-il des problemes avec certains protocoles comme FTP ou SIP ?', options: ['Le NAT est trop lent pour ces protocoles', 'Ces protocoles embarquent des adresses IP dans le payload (donnees applicatives) que le NAT ne traduit pas par defaut', 'Le NAT bloque automatiquement FTP et SIP', 'Ces protocoles n\'utilisent pas TCP/IP'], correct: 1, explanation: 'Certains protocoles (FTP, SIP, H.323) incluent des adresses IP et des ports dans le contenu des paquets (couche application), pas seulement dans les en-tetes IP. Le NAT standard ne modifie que les en-tetes, ce qui casse la communication. Des ALG (Application Layer Gateway) sont necessaires pour inspecter et modifier le payload.' },
  ],
  23: [
    { id: 'q23_1', question: 'Quelles sont les quatre etapes du processus DHCP dans l\'ordre correct ?', options: ['Discover, Offer, Request, Acknowledge (DORA)', 'Request, Discover, Acknowledge, Offer', 'Offer, Discover, Request, Acknowledge', 'Acknowledge, Request, Offer, Discover'], correct: 0, explanation: 'Le processus DHCP suit l\'ordre DORA : 1) Discover (client broadcast pour trouver un serveur), 2) Offer (serveur propose une adresse), 3) Request (client accepte l\'offre en broadcast), 4) Acknowledge (serveur confirme le bail). Les messages Discover et Request sont en broadcast, Offer et Acknowledge en unicast ou broadcast.' },
    { id: 'q23_2', question: 'Quelle commande Cisco configure un pool DHCP sur un routeur ?', options: ['dhcp pool LAN', 'ip dhcp pool LAN', 'service dhcp pool LAN', 'ip dhcp-server pool LAN'], correct: 1, explanation: 'La commande "ip dhcp pool [NOM]" entre dans le mode de configuration du pool DHCP. Ensuite on configure : "network [reseau] [masque]" pour la plage, "default-router [ip]" pour la passerelle, "dns-server [ip]" pour le DNS, et "lease [jours]" pour la duree du bail. Le service DHCP est actif par defaut sur les routeurs Cisco.' },
    { id: 'q23_3', question: 'Pourquoi un agent relais DHCP (ip helper-address) est-il necessaire ?', options: ['Pour accelerer le processus DHCP', 'Parce que les messages DHCP Discover sont en broadcast et ne traversent pas les routeurs', 'Pour chiffrer les echanges DHCP', 'Pour limiter le nombre de baux DHCP'], correct: 1, explanation: 'Les messages DHCP Discover du client sont envoyes en broadcast (255.255.255.255). Par defaut, un routeur ne transmet pas les broadcasts entre sous-reseaux. L\'agent relais DHCP (ip helper-address) intercepte ces broadcasts sur l\'interface locale et les retransmet en unicast vers le serveur DHCP distant, permettant un serveur DHCP centralise.' },
    { id: 'q23_4', question: 'Sur quelle interface configure-t-on la commande "ip helper-address" ?', options: ['Sur l\'interface connectee au serveur DHCP', 'Sur l\'interface du routeur cote clients (reseau sans serveur DHCP)', 'Sur l\'interface loopback', 'Sur toutes les interfaces du routeur'], correct: 1, explanation: 'La commande "ip helper-address [adresse-serveur-DHCP]" se configure sur l\'interface du routeur connectee au sous-reseau des clients. C\'est l\'interface qui recoit les broadcasts DHCP Discover. Le routeur convertit alors le broadcast en unicast et le transmet au serveur DHCP dont l\'adresse est specifiee.' },
    { id: 'q23_5', question: 'Quelle commande exclut des adresses IP d\'un pool DHCP (pour les equipements avec IP statique) ?', options: ['ip dhcp exclude 192.168.1.1 192.168.1.10', 'ip dhcp excluded-address 192.168.1.1 192.168.1.10', 'no ip dhcp pool 192.168.1.1', 'ip dhcp reserved 192.168.1.1 192.168.1.10'], correct: 1, explanation: 'La commande "ip dhcp excluded-address [debut] [fin]" exclut une plage d\'adresses du pool DHCP. Ces adresses ne seront jamais attribuees dynamiquement. Il faut exclure les adresses des routeurs, switches, serveurs et autres equipements configures en IP statique pour eviter les conflits d\'adresses.' },
    { id: 'q23_6', question: 'Quel port UDP utilise le client DHCP pour envoyer ses messages ?', options: ['Port 53', 'Port 67', 'Port 68', 'Port 546'], correct: 2, explanation: 'Le client DHCP utilise le port UDP 68 comme port source. Le serveur DHCP ecoute sur le port UDP 67. Les messages transitent exclusivement en UDP car le client n\'a pas encore d\'adresse IP et ne peut pas etablir de session TCP. Le couple de ports 67 (serveur) et 68 (client) est specifique au DHCP.' },
    { id: 'q23_7', question: 'Que se passe-t-il lorsqu\'un bail DHCP atteint 50% de sa duree ?', options: ['Le client perd son adresse immediatement', 'Le client envoie un DHCP Request en unicast au serveur pour renouveler le bail', 'Le serveur revoque le bail automatiquement', 'Le client envoie un nouveau Discover en broadcast'], correct: 1, explanation: 'A 50% du bail (T1), le client tente un renouvellement en envoyant un DHCP Request en unicast directement au serveur qui a attribue le bail. Si le serveur repond avec un ACK, le bail est renouvele. A 87.5% (T2), si T1 a echoue, le client tente un rebinding en broadcast vers n\'importe quel serveur DHCP.' },
    { id: 'q23_8', question: 'Quelle commande affiche les baux DHCP actifs sur un routeur Cisco servant de serveur DHCP ?', options: ['show ip dhcp pool', 'show ip dhcp binding', 'show ip dhcp server statistics', 'show ip dhcp conflict'], correct: 1, explanation: 'La commande "show ip dhcp binding" affiche la liste des adresses IP attribuees avec l\'adresse MAC du client, la date d\'expiration du bail et le type de bail. "show ip dhcp pool" affiche la configuration des pools. "show ip dhcp conflict" montre les conflits d\'adresses detectes. "show ip dhcp server statistics" affiche les compteurs DORA.' },
    { id: 'q23_9', question: 'Quel message DHCP un client envoie-t-il pour liberer volontairement son adresse IP ?', options: ['DHCP Decline', 'DHCP Release', 'DHCP Inform', 'DHCP NAK'], correct: 1, explanation: 'Le client envoie un DHCP Release en unicast au serveur pour liberer son bail avant expiration (par exemple lors d\'un "ipconfig /release" sous Windows). DHCP Decline indique que l\'adresse proposee est deja utilisee. DHCP Inform demande des parametres supplementaires sans nouvelle adresse. DHCP NAK est un refus du serveur.' },
    { id: 'q23_10', question: 'Quels autres protocoles, en plus de DHCP, sont retransmis par la commande "ip helper-address" ?', options: ['Uniquement DHCP', 'DHCP, DNS, TFTP, TACACS et NetBIOS entre autres (8 protocoles UDP)', 'Tous les protocoles TCP et UDP', 'Uniquement DHCP et DNS'], correct: 1, explanation: 'Par defaut, "ip helper-address" retransmet 8 protocoles UDP : DHCP (67/68), DNS (53), TFTP (69), TACACS (49), NetBIOS Name (137), NetBIOS Datagram (138), Time (37) et BootP. On peut restreindre avec "no ip forward-protocol udp [port]" pour ne relayer que DHCP si souhaite.' },
  ],
  24: [
    { id: 'q24_1', question: 'Quel type d\'enregistrement DNS associe un nom de domaine a une adresse IPv4 ?', options: ['AAAA', 'CNAME', 'A', 'MX'], correct: 2, explanation: 'L\'enregistrement A (Address) mappe un nom de domaine a une adresse IPv4. Exemple : netrevision.fr → 46.202.168.181. L\'enregistrement AAAA fait la meme chose pour IPv6. CNAME cree un alias vers un autre nom. MX designe les serveurs de messagerie du domaine.' },
    { id: 'q24_2', question: 'Quelle est la difference entre une requete DNS recursive et iterative ?', options: ['La recursive est plus lente', 'En recursive, le serveur DNS doit fournir la reponse finale ; en iterative, il peut renvoyer vers un autre serveur', 'L\'iterative est utilisee uniquement pour IPv6', 'Il n\'y a aucune difference'], correct: 1, explanation: 'Dans une requete recursive, le client demande au serveur DNS de lui fournir la reponse complete. Le serveur doit resoudre entierement le nom (en interrogeant d\'autres serveurs si besoin) avant de repondre. Dans une requete iterative, le serveur retourne la meilleure reponse qu\'il connait ou une reference vers un autre serveur DNS plus proche de la reponse.' },
    { id: 'q24_3', question: 'Quel enregistrement DNS est utilise pour rediriger les emails vers les serveurs de messagerie d\'un domaine ?', options: ['A', 'CNAME', 'MX', 'TXT'], correct: 2, explanation: 'L\'enregistrement MX (Mail Exchanger) indique quels serveurs gerent les emails pour un domaine. Il inclut une priorite (plus le nombre est bas, plus la priorite est haute). Exemple : netrevision.fr MX 5 mx1.hostinger.com, MX 10 mx2.hostinger.com. Le serveur avec la priorite la plus basse est contacte en premier.' },
    { id: 'q24_4', question: 'Quel est le role du cache DNS sur un poste client ?', options: ['Bloquer les sites malveillants', 'Stocker temporairement les resolutions DNS pour accelerer les requetes futures', 'Chiffrer les requetes DNS', 'Remplacer le serveur DNS'], correct: 1, explanation: 'Le cache DNS local stocke les reponses DNS deja obtenues avec leur TTL (Time To Live). Lorsqu\'un nom est demande a nouveau, le cache fournit la reponse instantanement sans interroger le serveur DNS. Cela reduit la latence et le trafic DNS. Sous Windows, "ipconfig /flushdns" vide le cache. Sous Linux, "systemd-resolve --flush-caches".' },
    { id: 'q24_5', question: 'Quel enregistrement DNS cree un alias pointant vers un autre nom de domaine ?', options: ['A', 'AAAA', 'CNAME', 'PTR'], correct: 2, explanation: 'L\'enregistrement CNAME (Canonical Name) cree un alias vers un autre nom de domaine. Exemple : www.netrevision.fr CNAME netrevision.fr. Le client resoudra ensuite netrevision.fr pour obtenir l\'IP. Un CNAME ne peut pas coexister avec d\'autres enregistrements pour le meme nom et ne doit pas pointer vers une IP directement.' },
    { id: 'q24_6', question: 'Quel port et quel protocole de transport utilise le DNS par defaut ?', options: ['TCP port 80', 'UDP port 53', 'TCP port 443', 'UDP port 161'], correct: 1, explanation: 'Le DNS utilise le port 53. Par defaut, les requetes standards utilisent UDP pour sa rapidite (pas de handshake). Si la reponse depasse 512 octets (ou 4096 avec EDNS), le DNS bascule sur TCP port 53 pour garantir la transmission complete. Les transferts de zone (AXFR) entre serveurs DNS utilisent aussi TCP.' },
    { id: 'q24_7', question: 'Quel type d\'enregistrement DNS est utilise pour la resolution inverse (adresse IP vers nom de domaine) ?', options: ['A', 'CNAME', 'PTR', 'SOA'], correct: 2, explanation: 'L\'enregistrement PTR (Pointer) est utilise pour le reverse DNS : il associe une adresse IP a un nom de domaine. Les enregistrements PTR sont stockes dans la zone in-addr.arpa (pour IPv4) ou ip6.arpa (pour IPv6). La resolution inverse est utilisee par les serveurs de messagerie pour verifier l\'identite des expediteurs (anti-spam).' },
    { id: 'q24_8', question: 'Quel est le role d\'un serveur DNS racine dans la hierarchie DNS ?', options: ['Il stocke tous les enregistrements DNS du monde', 'Il repond aux requetes pour les domaines .com et .fr', 'Il renvoie vers les serveurs TLD (Top-Level Domain) correspondants', 'Il sert de cache global pour Internet'], correct: 2, explanation: 'Les 13 groupes de serveurs racine (A a M) sont le point de depart de la resolution DNS. Ils ne connaissent pas les adresses finales mais renvoient les requetes vers les serveurs TLD (.com, .fr, .org, etc.) qui eux-memes renvoient vers les serveurs faisant autorite pour le domaine specifique. Les serveurs racine sont distribues via anycast dans le monde.' },
    { id: 'q24_9', question: 'Quel enregistrement DNS associe un nom de domaine a une adresse IPv6 ?', options: ['A', 'AAAA', 'A6', 'IPv6'], correct: 1, explanation: 'L\'enregistrement AAAA (quad-A) mappe un nom de domaine a une adresse IPv6 (128 bits). Il est l\'equivalent IPv6 de l\'enregistrement A. Exemple : netrevision.fr AAAA 2a06:98c1:3121::2. Un domaine peut avoir a la fois un enregistrement A (IPv4) et AAAA (IPv6) pour le dual-stack.' },
    { id: 'q24_10', question: 'Que signifie le TTL (Time To Live) dans un enregistrement DNS ?', options: ['La duree de vie du nom de domaine', 'Le nombre de sauts reseau maximum', 'La duree pendant laquelle un enregistrement DNS peut etre mis en cache avant de devoir etre actualise', 'Le temps de reponse du serveur DNS'], correct: 2, explanation: 'Le TTL DNS indique en secondes combien de temps un enregistrement peut rester en cache (chez les resolvers et les clients). Un TTL de 3600 signifie 1 heure de cache. Un TTL bas (60-300s) permet des changements rapides (migration), un TTL eleve (86400s) reduit le trafic DNS mais ralentit la propagation des modifications.' },
  ],
  25: [
    { id: 'q25_1', question: 'Quel est le role principal du protocole NTP dans un reseau ?', options: ['Transferer des fichiers entre equipements', 'Synchroniser les horloges de tous les equipements reseau sur une reference de temps commune', 'Superviser les performances du reseau', 'Attribuer des adresses IP dynamiquement'], correct: 1, explanation: 'NTP (Network Time Protocol) synchronise les horloges systeme des equipements reseau (routeurs, switches, serveurs, pare-feux) sur une source de temps precise. Une horloge synchronisee est essentielle pour la correlation des logs, le troubleshooting, les certificats numeriques, Kerberos et toute analyse forensique.' },
    { id: 'q25_2', question: 'Que represente le concept de "stratum" dans NTP ?', options: ['Le niveau de chiffrement', 'Le nombre de sauts entre un equipement et la source de temps de reference (horloge atomique)', 'La vitesse de synchronisation', 'Le nombre de serveurs NTP dans le reseau'], correct: 1, explanation: 'Le stratum indique la distance hierarchique par rapport a une horloge de reference (stratum 0 = horloge atomique/GPS). Un serveur NTP connecte directement a une horloge atomique est stratum 1. Un equipement synchronise sur un stratum 1 est stratum 2, et ainsi de suite. La valeur maximale est 15, stratum 16 signifie non synchronise.' },
    { id: 'q25_3', question: 'Quelle commande configure un routeur Cisco pour se synchroniser avec un serveur NTP ?', options: ['clock set ntp 192.168.1.1', 'ntp server 192.168.1.1', 'ntp peer 192.168.1.1', 'time-source 192.168.1.1'], correct: 1, explanation: 'La commande "ntp server [adresse-IP]" configure le routeur comme client NTP qui se synchronise sur le serveur specifie. "ntp peer" etablit une relation symetrique (les deux equipements se synchronisent mutuellement). On peut ajouter "prefer" pour indiquer le serveur prefere si plusieurs sont configures.' },
    { id: 'q25_4', question: 'Quel port UDP utilise NTP ?', options: ['Port 69', 'Port 123', 'Port 161', 'Port 514'], correct: 1, explanation: 'NTP utilise le port UDP 123 pour la communication entre clients et serveurs. UDP est prefere car les echanges NTP sont de simples requetes-reponses sans besoin de fiabilite TCP. Le protocole echange des timestamps pour calculer le decalage (offset) et le delai (delay) de transmission.' },
    { id: 'q25_5', question: 'Quelle commande verifie l\'etat de la synchronisation NTP sur un routeur Cisco ?', options: ['show clock', 'show ntp status', 'show ntp peers', 'show time'], correct: 1, explanation: 'La commande "show ntp status" affiche l\'etat de synchronisation : stratum du routeur, reference de temps, offset et delai. "show ntp associations" montre la liste des serveurs NTP configures et leur etat (*=synchronise, +=candidat). "show clock" affiche l\'heure actuelle du routeur mais pas les details NTP.' },
    { id: 'q25_6', question: 'Pourquoi la synchronisation NTP est-elle critique pour l\'analyse des logs ?', options: ['Les logs ne fonctionnent pas sans NTP', 'Sans horloges synchronisees, il est impossible de correler chronologiquement les evenements entre differents equipements', 'NTP compresse les logs automatiquement', 'NTP chiffre les logs en transit'], correct: 1, explanation: 'Lorsqu\'un incident de securite ou une panne survient, les administrateurs doivent correler les logs de multiples equipements (routeurs, pare-feux, serveurs) dans l\'ordre chronologique exact. Sans NTP, les horloges derivent et les timestamps des logs deviennent incoherents, rendant le diagnostic et l\'investigation forensique extremement difficiles.' },
    { id: 'q25_7', question: 'Quel mecanisme NTP permet de verifier l\'authenticite du serveur de temps ?', options: ['NTP chiffrement SSL', 'NTP authentication avec cles MD5 ou SHA', 'NTP certificate', 'NTP password'], correct: 1, explanation: 'L\'authentification NTP utilise des cles partagees (MD5 ou SHA) pour verifier que les mises a jour de temps proviennent d\'un serveur de confiance. Configuration : "ntp authentication-key [num] md5 [cle]", "ntp trusted-key [num]", "ntp authenticate". Cela empeche un attaquant de manipuler l\'horloge via un faux serveur NTP.' },
    { id: 'q25_8', question: 'Quelle est la difference entre les commandes "ntp server" et "ntp peer" ?', options: ['Il n\'y a aucune difference', '"ntp server" configure une relation client-serveur unidirectionnelle, "ntp peer" configure une synchronisation bidirectionnelle', '"ntp peer" est uniquement pour IPv6', '"ntp server" est obsolete'], correct: 1, explanation: 'Avec "ntp server", l\'equipement se synchronise sur le serveur distant (relation hierarchique). Avec "ntp peer", les deux equipements se synchronisent mutuellement (relation symetrique) : celui avec le stratum le plus bas fournit le temps a l\'autre. Le mode peer est utile entre equipements du meme niveau hierarchique.' },
    { id: 'q25_9', question: 'Quel est le stratum maximum utilisable dans NTP ?', options: ['Stratum 5', 'Stratum 10', 'Stratum 15', 'Stratum 255'], correct: 2, explanation: 'Le stratum maximum utilisable est 15. Le stratum 16 indique que l\'equipement n\'est pas synchronise et son horloge n\'est pas fiable. En pratique, les reseaux d\'entreprise utilisent des serveurs stratum 1 ou 2 publics, ce qui donne des equipements internes en stratum 2 ou 3. Il est recommande de ne pas depasser stratum 4-5.' },
    { id: 'q25_10', question: 'Quelle commande configure un routeur Cisco pour servir de source NTP (master) aux autres equipements du reseau local ?', options: ['ntp broadcast', 'ntp master [stratum]', 'ntp source loopback0', 'ntp enable server'], correct: 1, explanation: 'La commande "ntp master [stratum]" configure le routeur comme serveur NTP de reference pour le reseau local. Il utilise son horloge interne comme source. Le numero de stratum indique le niveau attribue (par defaut 8). Les autres equipements peuvent alors se synchroniser sur lui avec "ntp server [IP-du-master]".' },
  ],
  26: [
    { id: 'q26_1', question: 'Quelles sont les trois versions principales de SNMP et laquelle est recommandee pour la securite ?', options: ['v1, v2, v3 — v1 est recommandee', 'v1, v2c, v3 — v3 est recommandee car elle offre authentification et chiffrement', 'v2a, v2b, v2c — v2c est recommandee', 'v1, v2c, v4 — v4 est recommandee'], correct: 1, explanation: 'SNMP existe en trois versions : v1 (community strings en clair, tres peu securise), v2c (ajout de GetBulk et meilleurs messages d\'erreur, mais toujours community strings en clair), et v3 (authentification SHA/MD5 + chiffrement AES/DES). SNMPv3 est la seule version recommandee en production car v1/v2c transmettent les credentials en clair.' },
    { id: 'q26_2', question: 'Quel est le role de la MIB (Management Information Base) dans SNMP ?', options: ['Chiffrer les communications SNMP', 'Definir la structure hierarchique des objets gerables et leurs OIDs sur un equipement', 'Stocker les logs de l\'equipement', 'Router les traps SNMP vers le manager'], correct: 1, explanation: 'La MIB est une base de donnees hierarchique (arborescente) qui definit tous les objets gerables d\'un equipement : nom, type de donnees, droits d\'acces et OID unique. Chaque constructeur peut ajouter ses MIB proprietaires. Les MIB standard (MIB-II, RFC 1213) definissent les objets communs (interfaces, IP, TCP, UDP).' },
    { id: 'q26_3', question: 'Quelle operation SNMP permet au manager de modifier la valeur d\'un parametre sur un equipement (ex: desactiver une interface) ?', options: ['GET', 'GET-NEXT', 'SET', 'TRAP'], correct: 2, explanation: 'L\'operation SET permet au manager SNMP de modifier la valeur d\'un objet sur l\'agent (equipement). Par exemple, changer l\'etat admin d\'une interface (ifAdminStatus) a "down". GET lit une valeur, GET-NEXT lit la valeur suivante dans la MIB (pour parcourir une table), et TRAP est une notification envoyee par l\'agent vers le manager.' },
    { id: 'q26_4', question: 'Que represente la "community string" en SNMPv2c ?', options: ['Une cle de chiffrement AES', 'Un mot de passe en clair servant a authentifier les requetes SNMP', 'Un identifiant de groupe VLAN', 'Un numero de version du protocole'], correct: 1, explanation: 'La community string est un mot de passe textuel transmis en clair dans chaque message SNMPv1/v2c. Par convention, "public" est la community en lecture seule (RO) et "private" en lecture-ecriture (RW). Comme elle circule en clair sur le reseau, elle peut etre capturee par un sniffeur. C\'est pourquoi SNMPv3 avec authentification et chiffrement est recommande.' },
    { id: 'q26_5', question: 'Quelle commande Cisco configure la community string SNMP en lecture seule ?', options: ['snmp-server community MaCle RO', 'snmp community MaCle read-only', 'snmp-server enable traps MaCle', 'snmp-server host MaCle'], correct: 0, explanation: 'La commande "snmp-server community [string] RO" configure une community string en lecture seule. "RW" donnerait les droits en lecture-ecriture. On peut ajouter un numero d\'ACL a la fin pour restreindre les adresses IP autorisees a interroger l\'equipement : "snmp-server community MaCle RO 10".' },
    { id: 'q26_6', question: 'Quel composant SNMP s\'execute sur les equipements reseau geres (routeurs, switches) ?', options: ['Le manager SNMP', 'L\'agent SNMP', 'Le proxy SNMP', 'Le collecteur SNMP'], correct: 1, explanation: 'L\'agent SNMP est un processus logiciel qui s\'execute sur chaque equipement gere. Il maintient la MIB locale, repond aux requetes GET/SET du manager et envoie des traps en cas d\'evenement. Le manager (NMS - Network Management System) centralise la supervision en interrogeant les agents et en recevant les traps.' },
    { id: 'q26_7', question: 'Quel type de message SNMP permet au manager de parcourir une table entiere (ex: table des interfaces) efficacement ?', options: ['GET', 'SET', 'GET-BULK (SNMPv2c/v3)', 'INFORM'], correct: 2, explanation: 'GET-BULK, introduit dans SNMPv2c, permet de recuperer un grand nombre d\'objets en une seule requete (equivalent a de multiples GET-NEXT). C\'est ideal pour parcourir des tables MIB comme ifTable (interfaces) ou ipRouteTable (routes). Le parametre max-repetitions controle le nombre d\'objets retournes par requete.' },
    { id: 'q26_8', question: 'Quels sont les trois niveaux de securite definis par SNMPv3 ?', options: ['low, medium, high', 'noAuthNoPriv, authNoPriv, authPriv', 'read, write, admin', 'public, private, encrypted'], correct: 1, explanation: 'SNMPv3 definit trois niveaux de securite : noAuthNoPriv (ni authentification ni chiffrement, equivalent a v1/v2c), authNoPriv (authentification par MD5 ou SHA mais pas de chiffrement), et authPriv (authentification ET chiffrement AES ou DES). Le niveau authPriv est recommande pour la production.' },
    { id: 'q26_9', question: 'Quelle commande configure l\'envoi de traps SNMP vers un serveur de supervision sur un routeur Cisco ?', options: ['snmp-server trap-destination 10.0.0.100', 'snmp-server host 10.0.0.100 version 2c MaCle', 'snmp-server enable 10.0.0.100', 'snmp-server manager 10.0.0.100'], correct: 1, explanation: 'La commande "snmp-server host [adresse-IP] version [version] [community]" definit le destinataire des traps (et informs). "snmp-server enable traps" active l\'envoi de traps pour des categories specifiques (interface, config, etc.). Sans "enable traps", aucun trap n\'est envoye meme si un host est configure.' },
    { id: 'q26_10', question: 'Quelle est la difference entre un SNMP Trap et un SNMP Inform ?', options: ['Le Trap est plus securise', 'Le Trap est envoye en "fire and forget" (UDP, sans acquittement), l\'Inform attend un acquittement du manager', 'L\'Inform est uniquement disponible en SNMPv1', 'Il n\'y a aucune difference'], correct: 1, explanation: 'Un Trap est envoye en UDP sans mecanisme de confirmation : si le message est perdu, l\'agent ne le sait pas. Un Inform (introduit en SNMPv2c) attend un acquittement du manager et retransmet le message si aucune reponse n\'est recue. Les Informs sont plus fiables mais generent plus de trafic. Les deux utilisent UDP port 162 cote manager.' },
  ],
  27: [
    { id: 'q27_1', question: 'Quels sont les niveaux de severite syslog de 0 (le plus critique) a 7 (le moins critique) ?', options: ['Debug, Info, Notice, Warning, Error, Critical, Alert, Emergency', 'Emergency, Alert, Critical, Error, Warning, Notice, Informational, Debug', 'Fatal, Error, Warn, Info, Debug, Trace, Verbose, All', 'Critical, Major, Minor, Warning, Info, Debug, Trace, None'], correct: 1, explanation: 'Les 8 niveaux syslog (RFC 5424) sont : 0-Emergency (systeme inutilisable), 1-Alert (action immediate requise), 2-Critical (conditions critiques), 3-Error (erreurs), 4-Warning (avertissements), 5-Notice (evenements normaux mais significatifs), 6-Informational (messages informatifs), 7-Debug (messages de debogage).' },
    { id: 'q27_2', question: 'Quelle commande configure un routeur Cisco pour envoyer ses logs vers un serveur syslog distant ?', options: ['syslog server 10.0.0.50', 'logging host 10.0.0.50', 'logging server 10.0.0.50', 'syslog enable 10.0.0.50'], correct: 1, explanation: 'La commande "logging host [adresse-IP]" (ou "logging [adresse-IP]") configure le routeur pour envoyer ses messages syslog vers un serveur distant. Par defaut, les messages sont envoyes en UDP sur le port 514. On peut configurer plusieurs serveurs syslog pour la redondance.' },
    { id: 'q27_3', question: 'Quel port et protocole utilise syslog par defaut ?', options: ['TCP 514', 'UDP 514', 'UDP 162', 'TCP 1514'], correct: 1, explanation: 'Syslog utilise par defaut le port UDP 514. UDP est rapide mais n\'offre pas de garantie de livraison (les logs peuvent etre perdus en cas de congestion). Pour plus de fiabilite, on peut utiliser TCP 514 ou TCP 6514 (syslog over TLS, RFC 5425). Les solutions modernes (rsyslog, syslog-ng) supportent TCP et TLS.' },
    { id: 'q27_4', question: 'Quelle commande definit le niveau de severite minimum des messages envoyes au serveur syslog sur un routeur Cisco ?', options: ['logging trap debugging', 'logging level warnings', 'logging severity 4', 'logging trap warnings'], correct: 3, explanation: 'La commande "logging trap [niveau]" definit le niveau de severite minimum envoye au serveur syslog. "logging trap warnings" (niveau 4) envoie les messages de niveau 0 a 4 (emergency a warning). "logging trap debugging" (niveau 7) envoie tout. Les niveaux acceptes sont les noms (emergencies, alerts, critical, errors, warnings, notifications, informational, debugging) ou les numeros (0-7).' },
    { id: 'q27_5', question: 'Ou les messages syslog sont-ils stockes localement par defaut sur un routeur Cisco ?', options: ['Dans la flash', 'Dans la NVRAM', 'Dans le buffer RAM (logging buffer)', 'Dans un fichier sur le disque'], correct: 2, explanation: 'Par defaut, les messages syslog sont stockes dans un buffer en RAM (logging buffered). La taille par defaut est de 4096 octets et peut etre augmentee avec "logging buffered [taille]". Les messages sont aussi affiches sur la console (logging console) et sur les lignes VTY (logging monitor). Le buffer est perdu au redemarrage.' },
    { id: 'q27_6', question: 'Quelle commande affiche les messages syslog stockes dans le buffer du routeur ?', options: ['show syslog', 'show logging', 'show log buffer', 'debug logging'], correct: 1, explanation: 'La commande "show logging" affiche la configuration syslog (destinations, niveaux) et les messages stockes dans le buffer local. Elle montre aussi le nombre de messages par niveau de severite. "terminal monitor" est necessaire pour voir les logs en temps reel sur une session VTY (SSH/Telnet).' },
    { id: 'q27_7', question: 'Quelle est la "facility" syslog et a quoi sert-elle ?', options: ['Elle definit la vitesse d\'envoi des logs', 'Elle identifie la source ou le type de processus qui a genere le message (kern, auth, local0-7, etc.)', 'Elle chiffre les messages syslog', 'Elle compresse les logs avant envoi'], correct: 1, explanation: 'La facility syslog identifie le sous-systeme qui a genere le message : kern (noyau), auth (authentification), mail, daemon, local0 a local7 (usage personnalise), etc. Sur un routeur Cisco, "logging facility local7" envoie les logs avec la facility local7. Le serveur syslog peut filtrer et stocker les logs dans des fichiers differents selon la facility.' },
    { id: 'q27_8', question: 'Pourquoi est-il recommande d\'ajouter des timestamps aux messages syslog ?', options: ['Pour reduire la taille des messages', 'Pour pouvoir correler les evenements dans le temps et faciliter le diagnostic', 'Pour chiffrer les messages', 'Les timestamps sont ajoutes automatiquement sans configuration'], correct: 1, explanation: 'La commande "service timestamps log datetime msec" ajoute un horodatage precis (date, heure, millisecondes) a chaque message syslog. Sans cela, les messages n\'ont pas de reference temporelle fiable, rendant impossible la correlation des evenements entre equipements. Combinee avec NTP, cette configuration est essentielle pour le troubleshooting.' },
    { id: 'q27_9', question: 'Quel niveau de severite syslog correspond a un message de debogage (debug) ?', options: ['Niveau 0', 'Niveau 3', 'Niveau 5', 'Niveau 7'], correct: 3, explanation: 'Le niveau 7 (Debug) est le moins critique et le plus verbeux. Il genere un grand volume de messages detailles utiles pour le depannage. En production, on configure generalement "logging trap informational" (niveau 6) ou "logging trap warnings" (niveau 4) pour eviter de surcharger le serveur syslog avec les messages debug.' },
    { id: 'q27_10', question: 'Quelle est la difference entre "logging console" et "logging monitor" sur un equipement Cisco ?', options: ['Il n\'y a aucune difference', '"logging console" envoie les logs sur le port console physique, "logging monitor" envoie sur les sessions VTY (SSH/Telnet)', '"logging monitor" est pour SNMP', '"logging console" est obsolete'], correct: 1, explanation: '"logging console [niveau]" controle les messages affiches sur le port console physique (lent, peut impacter les performances si trop verbeux). "logging monitor [niveau]" controle les messages envoyes aux sessions VTY distantes (SSH/Telnet), mais necessite "terminal monitor" dans chaque session pour activer l\'affichage.' },
  ],
  28: [
    { id: 'q28_1', question: 'Quel est l\'objectif principal de la QoS (Quality of Service) dans un reseau ?', options: ['Augmenter la bande passante totale', 'Prioriser certains types de trafic pour garantir des performances acceptables quand le reseau est congestionne', 'Chiffrer le trafic sensible', 'Compresser tous les paquets'], correct: 1, explanation: 'La QoS ne cree pas de bande passante supplementaire. Elle permet de gerer la congestion en priorisant le trafic critique (voix, video) par rapport au trafic moins sensible (email, telechargement). Sans QoS, tous les paquets sont traites de maniere identique (best-effort) et le trafic temps-reel peut souffrir de latence, gigue et perte de paquets.' },
    { id: 'q28_2', question: 'Quel champ de l\'en-tete IP est utilise par DSCP pour marquer les paquets avec une classe de QoS ?', options: ['TTL', 'Le champ ToS (Type of Service) / DS field (8 bits dont 6 pour DSCP)', 'Le champ Protocol', 'Le champ Checksum'], correct: 1, explanation: 'Le champ DS (Differentiated Services) occupe les 8 bits du champ ToS de l\'en-tete IPv4. Les 6 premiers bits forment le DSCP (Differentiated Services Code Point) offrant 64 valeurs possibles (0-63). Les 2 derniers bits sont ECN (Explicit Congestion Notification). DSCP a remplace l\'ancien systeme IP Precedence (3 bits).' },
    { id: 'q28_3', question: 'Quelle valeur DSCP est recommandee pour le trafic voix (VoIP) selon les bonnes pratiques Cisco ?', options: ['DSCP 0 (Best Effort)', 'DSCP 26 (AF31)', 'DSCP 46 (EF - Expedited Forwarding)', 'DSCP 8 (CS1)'], correct: 2, explanation: 'DSCP EF (Expedited Forwarding, valeur 46) est la classe recommandee pour le trafic voix. Elle garantit faible latence, faible gigue et faible perte de paquets. La voix necessite moins de 150ms de latence one-way, moins de 30ms de gigue et moins de 1% de perte. Le trafic de signalisation (SIP) utilise generalement CS3 (DSCP 24).' },
    { id: 'q28_4', question: 'Quelle est la difference entre le policing et le shaping en QoS ?', options: ['Le policing est plus rapide', 'Le policing supprime (drop) les paquets excessifs immediatement, le shaping les met en file d\'attente et les retarde pour lisser le trafic', 'Le shaping est uniquement pour IPv6', 'Il n\'y a aucune difference'], correct: 1, explanation: 'Le policing surveille le debit et supprime (drop) ou re-marque les paquets qui depassent le debit autorise. C\'est brutal mais sans delai. Le shaping (mise en forme) met en buffer les paquets excessifs et les envoie progressivement pour lisser le trafic selon le debit cible. Le shaping introduit de la latence mais evite les pertes. Le shaping est prefere pour les liens WAN.' },
    { id: 'q28_5', question: 'Qu\'est-ce que la "trust boundary" (frontiere de confiance) en QoS ?', options: ['Le perimetre du pare-feu', 'Le point du reseau a partir duquel les marquages QoS des equipements sont consideres comme fiables', 'La limite entre Internet et le LAN', 'Le seuil de debit maximum'], correct: 1, explanation: 'La trust boundary est le point ou le reseau commence a faire confiance aux marquages QoS. Typiquement, elle se situe au niveau du switch d\'acces ou du telephone IP. Les paquets venant de PC non fiables voient leur marquage remis a zero (DSCP 0). Les telephones IP Cisco marquent eux-memes la voix en EF et la signalisation en CS3.' },
    { id: 'q28_6', question: 'Quel mecanisme de QoS place les paquets dans differentes files d\'attente selon leur priorite avant la transmission ?', options: ['Classification', 'Marking', 'Queuing (mise en file d\'attente)', 'Congestion avoidance'], correct: 2, explanation: 'Le queuing (mise en file d\'attente) utilise plusieurs files pour separer les trafics par priorite. Les algorithmes incluent : Priority Queuing (PQ), Weighted Fair Queuing (WFQ), Class-Based WFQ (CBWFQ) et Low Latency Queuing (LLQ). LLQ combine CBWFQ avec une file prioritaire strict pour la voix, offrant le meilleur des deux mondes.' },
    { id: 'q28_7', question: 'Quel mecanisme QoS supprime proactivement des paquets avant que la file d\'attente ne soit pleine pour eviter la congestion ?', options: ['Tail drop', 'WRED (Weighted Random Early Detection)', 'Policing', 'Traffic shaping'], correct: 1, explanation: 'WRED (Weighted Random Early Detection) commence a supprimer aleatoirement des paquets quand la file d\'attente approche un seuil configurable, avant qu\'elle ne soit pleine. Les paquets de faible priorite sont supprimes en premier. Cela evite le "tail drop" (tous les paquets supprimes quand la file est pleine) et la synchronisation TCP globale.' },
    { id: 'q28_8', question: 'Quelle est la difference entre la classification et le marquage en QoS ?', options: ['Ce sont des synonymes', 'La classification identifie le type de trafic, le marquage inscrit la priorite dans l\'en-tete du paquet', 'Le marquage identifie le trafic et la classification l\'inscrit', 'La classification est uniquement pour la voix'], correct: 1, explanation: 'La classification examine le trafic pour l\'identifier (par port, adresse, protocole, NBAR). Le marquage ecrit la valeur de priorite dans l\'en-tete du paquet (DSCP dans IP, CoS dans 802.1Q). La classification se fait idealement une seule fois, le plus pres possible de la source, puis les equipements suivants se basent sur le marquage pour appliquer la QoS.' },
    { id: 'q28_9', question: 'Que signifie le sigle CoS (Class of Service) en QoS et ou est-il applique ?', options: ['C\'est un champ dans l\'en-tete IP', 'C\'est un champ de 3 bits dans le tag 802.1Q (trame Ethernet sur un trunk)', 'C\'est un protocole de routage', 'C\'est un type de chiffrement'], correct: 1, explanation: 'CoS (Class of Service) est un champ de 3 bits situe dans le tag 802.1Q des trames Ethernet sur les liens trunk. Il permet 8 valeurs (0-7). CoS 5 est generalement utilise pour la voix. Contrairement a DSCP qui est dans l\'en-tete IP (couche 3), CoS est au niveau couche 2 et est perdu quand le paquet est route (le tag 802.1Q est retire).' },
    { id: 'q28_10', question: 'Quel modele de QoS est base sur le marquage DSCP et traite les paquets par classe (PHB) a chaque noeud du reseau ?', options: ['IntServ (Integrated Services)', 'Best Effort', 'DiffServ (Differentiated Services)', 'RSVP'], correct: 2, explanation: 'DiffServ classe les paquets au bord du reseau (marquage DSCP) puis chaque noeud interne applique un comportement par saut (PHB - Per-Hop Behavior) selon le DSCP. C\'est simple et evolutif. IntServ utilise RSVP pour reserver des ressources de bout en bout pour chaque flux : plus precis mais peu scalable. DiffServ est le modele dominant aujourd\'hui.' },
  ],
  29: [
    { id: 'q29_1', question: 'Quelle version de SSH est recommandee et pourquoi ne faut-il pas utiliser SSHv1 ?', options: ['SSHv1 est recommande car plus rapide', 'SSHv2 est recommande car SSHv1 a des vulnerabilites connues permettant le vol de session et l\'interception', 'Les deux versions sont equivalentes', 'SSHv3 est la version actuelle recommandee'], correct: 1, explanation: 'SSHv2 est la seule version recommandee. SSHv1 contient des vulnerabilites cryptographiques connues (man-in-the-middle, injection de donnees dans le flux chiffre). La commande "ip ssh version 2" force l\'utilisation de SSHv2. SSHv3 n\'existe pas en tant que standard; la version actuelle est SSHv2 (RFC 4253).' },
    { id: 'q29_2', question: 'Quelle est la premiere etape obligatoire pour configurer SSH sur un routeur Cisco ?', options: ['Configurer les lignes VTY', 'Definir un hostname et un domain-name (necessaires pour generer les cles RSA)', 'Creer un utilisateur', 'Activer le service SSH'], correct: 1, explanation: 'Avant de generer les cles RSA, le routeur doit avoir un hostname (hostname R1) et un domain-name (ip domain-name entreprise.local) car ces elements sont utilises pour construire le nom de la cle RSA. Sans eux, la commande "crypto key generate rsa" echoue. L\'ordre est : hostname → domain-name → crypto key → VTY → user.' },
    { id: 'q29_3', question: 'Quelle commande genere les cles RSA necessaires au fonctionnement de SSH sur un equipement Cisco ?', options: ['ssh keygen rsa 2048', 'crypto key generate rsa general-keys modulus 2048', 'generate ssh-key rsa 2048', 'ip ssh rsa-key 2048'], correct: 1, explanation: 'La commande "crypto key generate rsa general-keys modulus [taille]" genere la paire de cles RSA (publique/privee). La taille recommandee est au minimum 2048 bits (1024 est considere comme faible). Une fois les cles generees, le service SSH est automatiquement active sur l\'equipement.' },
    { id: 'q29_4', question: 'Quelle commande restreint les lignes VTY pour accepter uniquement les connexions SSH (et refuser Telnet) ?', options: ['transport input ssh', 'no telnet enable', 'ssh only', 'line vty 0 4 ssh-only'], correct: 0, explanation: 'La commande "transport input ssh" appliquee sous les lignes VTY (line vty 0 4 ou 0 15) restreint l\'acces distant a SSH uniquement. "transport input telnet ssh" autoriserait les deux. "transport input none" desactiverait tout acces distant. Par defaut, certaines versions d\'IOS autorisent Telnet et SSH.' },
    { id: 'q29_5', question: 'Pourquoi Telnet est-il considere comme non securise pour l\'administration des equipements reseau ?', options: ['Telnet est trop lent', 'Telnet transmet toutes les donnees en clair (y compris les identifiants) sans aucun chiffrement', 'Telnet ne supporte pas les commandes show', 'Telnet fonctionne uniquement en IPv4'], correct: 1, explanation: 'Telnet (port TCP 23) transmet tout en clair : noms d\'utilisateur, mots de passe, commandes et reponses. Un attaquant avec un sniffer (Wireshark) sur le meme reseau peut capturer toutes les informations. SSH (port TCP 22) chiffre l\'integralite de la session avec des algorithmes comme AES, rendant l\'interception inutile.' },
    { id: 'q29_6', question: 'Quelle commande configure le nombre maximum de tentatives d\'authentification SSH avant deconnexion ?', options: ['ip ssh max-retries 3', 'ip ssh authentication-retries 3', 'ssh max-attempts 3', 'login block-for 120 attempts 3'], correct: 1, explanation: 'La commande "ip ssh authentication-retries [nombre]" definit le nombre de tentatives d\'authentification autorisees avant de deconnecter la session SSH (par defaut 3). "ip ssh time-out [secondes]" definit le delai d\'inactivite. "login block-for" est une protection contre le brute-force qui bloque les tentatives pendant un delai.' },
    { id: 'q29_7', question: 'Quelle methode d\'authentification est la plus securisee pour SSH sur un equipement Cisco ?', options: ['Mot de passe simple sur la ligne VTY', 'Authentification par cle publique RSA', 'Authentification par community string', 'Aucune authentification'], correct: 1, explanation: 'L\'authentification par cle publique RSA est la plus securisee car elle ne transmet jamais de mot de passe sur le reseau. Le client prouve sa possession de la cle privee sans la reveler. Sur Cisco IOS, on peut configurer "ip ssh pubkey-chain" et stocker les cles publiques des administrateurs autorises.' },
    { id: 'q29_8', question: 'Combien de lignes VTY sont disponibles par defaut sur un routeur Cisco et a quoi servent-elles ?', options: ['1 ligne pour la console uniquement', '5 lignes (VTY 0-4) pour les connexions distantes simultanees, extensibles a 16 (VTY 0-15)', '100 lignes pour les connexions SSH', '2 lignes : une pour Telnet, une pour SSH'], correct: 1, explanation: 'Par defaut, un routeur Cisco dispose de 5 lignes VTY (0 a 4) permettant 5 sessions distantes simultanees (SSH ou Telnet). On peut configurer jusqu\'a 16 lignes (VTY 0 a 15) sur la plupart des plateformes. Chaque ligne VTY est independante et peut avoir ses propres parametres de securite (ACL, transport input, authentication).' },
    { id: 'q29_9', question: 'Quelle commande verifie les sessions SSH actives sur un routeur Cisco ?', options: ['show ssh', 'show sessions', 'show users ssh', 'show ip ssh connections'], correct: 0, explanation: 'La commande "show ssh" affiche les sessions SSH actives avec l\'utilisateur, la version SSH utilisee, l\'etat de la connexion et le chiffrement. "show ip ssh" affiche la configuration SSH globale (version, timeout, retries). "show users" affiche toutes les sessions actives (console + VTY) mais sans les details SSH specifiques.' },
    { id: 'q29_10', question: 'Quelle commande applique une ACL sur les lignes VTY pour restreindre les adresses IP autorisees a se connecter en SSH ?', options: ['ip access-group 10 in', 'access-class 10 in', 'access-list 10 permit ssh', 'ip ssh access 10'], correct: 1, explanation: 'La commande "access-class [numero-ACL] in" s\'applique sous les lignes VTY pour filtrer les connexions entrantes par adresse IP source. "ip access-group" s\'utilise sur les interfaces physiques ou logiques, pas sur les VTY. Exemple : access-list 10 permit 192.168.1.0 0.0.0.255, puis sous line vty 0 4 : access-class 10 in.' },
  ],
  30: [
    { id: 'q30_1', question: 'Quel protocole de transfert de fichiers utilise UDP et est tres simple mais sans authentification ni chiffrement ?', options: ['FTP', 'SFTP', 'TFTP', 'SCP'], correct: 2, explanation: 'TFTP (Trivial File Transfer Protocol) utilise UDP port 69. Il est extremement simple (pas d\'authentification, pas de chiffrement, pas de listing de repertoires) et leger. Il est couramment utilise pour transferer des images IOS et des fichiers de configuration vers/depuis les equipements reseau. Sa simplicite le rend ideal pour les environnements embarques.' },
    { id: 'q30_2', question: 'Quelle commande Cisco copie l\'image IOS d\'un serveur TFTP vers la memoire flash du routeur ?', options: ['tftp get flash:', 'copy tftp: flash:', 'download tftp flash:', 'transfer tftp to flash:'], correct: 1, explanation: 'La commande "copy tftp: flash:" lance un assistant interactif demandant l\'adresse du serveur TFTP, le nom du fichier source et le nom du fichier de destination. On peut aussi specifier directement : "copy tftp://10.0.0.1/image.bin flash:". Cette commande est utilisee pour les mises a jour IOS et la restauration d\'images.' },
    { id: 'q30_3', question: 'Quel port utilise FTP pour le canal de controle (commandes) ?', options: ['Port 20', 'Port 21', 'Port 22', 'Port 69'], correct: 1, explanation: 'FTP utilise deux canaux : le port TCP 21 pour le controle (envoi des commandes et reponses) et le port TCP 20 pour le transfert de donnees (en mode actif). En mode passif, le canal de donnees utilise un port aleatoire negocie. TFTP utilise UDP 69 et SFTP/SCP utilisent TCP 22 (tunnel SSH).' },
    { id: 'q30_4', question: 'Quelle commande sauvegarde la running-config vers un serveur TFTP ?', options: ['copy startup-config tftp:', 'copy running-config tftp:', 'backup config tftp:', 'save config tftp:'], correct: 1, explanation: 'La commande "copy running-config tftp:" sauvegarde la configuration active du routeur vers un serveur TFTP. Le routeur demande l\'adresse du serveur et le nom du fichier de destination. Pour restaurer : "copy tftp: running-config" (merge) ou "copy tftp: startup-config" suivi d\'un reload (remplacement complet).' },
    { id: 'q30_5', question: 'Quelle est la difference principale entre FTP et TFTP ?', options: ['FTP est plus rapide', 'FTP supporte l\'authentification (login/password), le listing de repertoires et TCP, tandis que TFTP est minimaliste avec UDP et sans authentification', 'TFTP est plus securise', 'Il n\'y a aucune difference significative'], correct: 1, explanation: 'FTP est un protocole complet : authentification par login/password, listing de repertoires, modes binaire/ASCII, reprise de transfert. Il utilise TCP (fiable). TFTP est minimaliste : pas d\'authentification, pas de listing, pas de reprise. Il utilise UDP et ne sait que lire (get) ou ecrire (put) des fichiers. TFTP est utilise pour sa simplicite sur les equipements reseau.' },
    { id: 'q30_6', question: 'Comment configurer un routeur Cisco pour utiliser un serveur FTP avec des identifiants ?', options: ['ftp login user password', 'ip ftp username [user] et ip ftp password [pass]', 'ftp-server enable user pass', 'copy ftp: flash: --user --pass'], correct: 1, explanation: 'Les commandes "ip ftp username [utilisateur]" et "ip ftp password [mot-de-passe]" configurent les identifiants FTP par defaut sur le routeur. Ensuite, "copy ftp: flash:" ou "copy running-config ftp:" utilise automatiquement ces identifiants. Sans cette configuration, le routeur demande les identifiants de maniere interactive.' },
    { id: 'q30_7', question: 'Quelle commande affiche les fichiers present dans la memoire flash d\'un routeur Cisco ?', options: ['dir flash:', 'show flash:', 'ls flash:', 'Les deux premieres reponses sont correctes (dir flash: et show flash:)'], correct: 3, explanation: '"show flash:" et "dir flash:" affichent le contenu de la memoire flash, incluant les images IOS, les fichiers de configuration sauvegardes et l\'espace disponible. "show flash:" est plus synthetique tandis que "dir flash:" montre plus de details (taille, date). "verify /md5 flash:[fichier]" verifie l\'integrite d\'un fichier.' },
    { id: 'q30_8', question: 'Quel protocole securise est recommande pour remplacer FTP car il chiffre les transferts via un tunnel SSH ?', options: ['TFTP', 'FTPS', 'SFTP ou SCP', 'HTTP'], correct: 2, explanation: 'SFTP (SSH File Transfer Protocol) et SCP (Secure Copy Protocol) utilisent SSH (port 22) pour chiffrer les transferts. Contrairement a FTP qui transmet les identifiants en clair, SFTP/SCP protegent toutes les donnees. Sur Cisco IOS, "copy scp: flash:" permet de transferer des fichiers via SCP. FTPS (FTP over SSL/TLS) est une alternative mais moins courante en reseau.' },
    { id: 'q30_9', question: 'Quelle commande restaure la startup-config depuis un serveur TFTP sur un routeur Cisco ?', options: ['restore tftp: startup-config', 'copy tftp: startup-config', 'load tftp startup-config', 'merge tftp: startup-config'], correct: 1, explanation: 'La commande "copy tftp: startup-config" telecharge un fichier de configuration depuis le serveur TFTP et l\'ecrit dans la startup-config (NVRAM). Apres un "reload", le routeur demarre avec cette configuration. Attention : "copy tftp: running-config" ne remplace pas la config, il fusionne (merge) la nouvelle avec l\'existante.' },
    { id: 'q30_10', question: 'En mode FTP actif, quel port est utilise pour le transfert de donnees ?', options: ['Port 21', 'Port 20', 'Port 22', 'Un port aleatoire cote serveur'], correct: 1, explanation: 'En mode FTP actif, le serveur initie la connexion de donnees depuis son port 20 vers un port aleatoire du client. En mode passif, c\'est le client qui initie la connexion vers un port aleatoire du serveur. Le mode passif est prefere car il traverse mieux les pare-feux et le NAT (le client initie les deux connexions).' },
  ],
  31: [
    { id: 'q31_1', question: 'Quel protocole FHRP (First Hop Redundancy Protocol) est proprietaire Cisco et utilise les termes Active et Standby ?', options: ['VRRP', 'GLBP', 'HSRP', 'CARP'], correct: 2, explanation: 'HSRP (Hot Standby Router Protocol) est un protocole proprietaire Cisco. Il utilise un routeur Active (qui transmet le trafic) et un routeur Standby (en attente). L\'IP virtuelle et la MAC virtuelle (0000.0c07.acXX) sont partagees. VRRP est le standard ouvert (IETF) avec les termes Master/Backup. GLBP est aussi Cisco mais offre le load balancing.' },
    { id: 'q31_2', question: 'Quel protocole FHRP est un standard ouvert (RFC 5798) interoperable entre constructeurs ?', options: ['HSRP', 'GLBP', 'VRRP', 'STP'], correct: 2, explanation: 'VRRP (Virtual Router Redundancy Protocol, RFC 5798) est le standard IETF ouvert. Il est similaire a HSRP mais interoperable entre constructeurs (Cisco, Juniper, Arista, etc.). Il utilise Master (routeur actif) et Backup (en attente). La priorite par defaut est 100. L\'adresse MAC virtuelle est 0000.5e00.01XX.' },
    { id: 'q31_3', question: 'Quel avantage unique offre GLBP par rapport a HSRP et VRRP ?', options: ['Meilleure securite', 'Load balancing natif du trafic entre plusieurs routeurs via differentes MAC virtuelles', 'Convergence plus rapide', 'Support d\'IPv6 uniquement'], correct: 1, explanation: 'GLBP (Gateway Load Balancing Protocol) est le seul FHRP a offrir un load balancing natif. Un AVG (Active Virtual Gateway) repond aux requetes ARP avec differentes MAC virtuelles assignees a differents AVF (Active Virtual Forwarders). Chaque client recoit la meme IP virtuelle mais une MAC differente, repartissant le trafic entre les routeurs.' },
    { id: 'q31_4', question: 'Quelle est la priorite par defaut dans HSRP et comment determiner quel routeur devient Active ?', options: ['Priorite 50, le routeur avec la priorite la plus basse gagne', 'Priorite 100, le routeur avec la priorite la plus haute devient Active (en cas d\'egalite, la plus haute IP gagne)', 'Priorite 255, election aleatoire', 'Priorite 1, le premier routeur demarre gagne'], correct: 1, explanation: 'La priorite HSRP par defaut est 100 (plage 0-255). Le routeur avec la priorite la plus haute devient Active. En cas d\'egalite, le routeur avec l\'adresse IP la plus haute sur l\'interface HSRP gagne. La commande "standby [group] priority [valeur]" modifie la priorite.' },
    { id: 'q31_5', question: 'Que fait la fonctionnalite "preemption" dans HSRP ?', options: ['Elle desactive le protocole HSRP', 'Elle permet a un routeur de priorite superieure de reprendre automatiquement le role Active quand il revient en ligne', 'Elle bloque les routeurs Standby', 'Elle change la MAC virtuelle'], correct: 1, explanation: 'La preemption (standby [group] preempt) permet a un routeur qui revient en ligne avec une priorite superieure de reprendre le role Active automatiquement. Sans preemption (comportement par defaut), le routeur Active en place conserve son role meme si un routeur de priorite superieure rejoint le groupe.' },
    { id: 'q31_6', question: 'Quelle est la commande Cisco pour configurer l\'adresse IP virtuelle HSRP sur un groupe ?', options: ['hsrp [group] ip [adresse]', 'standby [group] ip [adresse]', 'virtual-ip [group] [adresse]', 'gateway [group] ip [adresse]'], correct: 1, explanation: 'La commande "standby [group-number] ip [adresse-IP-virtuelle]" configure l\'adresse IP virtuelle que les clients utiliseront comme passerelle par defaut. Le numero de groupe (0-255 pour HSRPv1, 0-4095 pour HSRPv2) identifie l\'instance HSRP. Tous les routeurs du meme groupe doivent partager la meme IP virtuelle.' },
    { id: 'q31_7', question: 'Quel est l\'intervalle Hello par defaut de HSRP et quel est le timer Hold ?', options: ['Hello 1s, Hold 3s', 'Hello 3s, Hold 10s', 'Hello 5s, Hold 15s', 'Hello 10s, Hold 30s'], correct: 1, explanation: 'Par defaut, HSRP envoie des messages Hello toutes les 3 secondes et le timer Hold est de 10 secondes. Si le routeur Standby ne recoit aucun Hello du routeur Active pendant 10 secondes, il prend le relais. On peut reduire ces timers pour une convergence plus rapide : "standby [group] timers [hello] [hold]" ou utiliser des timers en millisecondes.' },
    { id: 'q31_8', question: 'Que permet le tracking d\'interface dans HSRP ?', options: ['Surveiller la bande passante des interfaces', 'Reduire automatiquement la priorite HSRP si une interface surveillee tombe, declenchant un basculement', 'Compter le nombre de paquets par interface', 'Desactiver l\'interface HSRP en cas de surcharge'], correct: 1, explanation: 'Le tracking d\'interface ("standby [group] track [interface] [decrement]") permet de reduire automatiquement la priorite HSRP si une interface critique (ex: lien WAN) tombe. Si la priorite descend en dessous de celle du routeur Standby et que la preemption est activee, un basculement se produit. Cela evite un routeur Active sans chemin vers Internet.' },
    { id: 'q31_9', question: 'Quelle adresse MAC virtuelle est utilisee par HSRP version 1 ?', options: ['0000.0c07.acXX (ou XX est le numero de groupe en hexadecimal)', '0000.5e00.01XX', '0007.b400.XXYY', 'L\'adresse MAC reelle du routeur Active'], correct: 0, explanation: 'HSRP version 1 utilise l\'adresse MAC virtuelle 0000.0c07.acXX, ou XX represente le numero de groupe en hexadecimal. HSRPv2 utilise 0000.0c9f.fXXX. VRRP utilise 0000.5e00.01XX. GLBP utilise 0007.b400.XXYY. Ces MAC virtuelles permettent aux clients de continuer a communiquer sans changement apres un basculement.' },
    { id: 'q31_10', question: 'Quelle est la difference entre HSRPv1 et HSRPv2 ?', options: ['HSRPv2 est un standard ouvert', 'HSRPv2 supporte plus de groupes (0-4095 vs 0-255), utilise le multicast 224.0.0.102 et des adresses MAC etendues', 'HSRPv1 est plus rapide', 'HSRPv2 ne supporte pas la preemption'], correct: 1, explanation: 'HSRPv2 etend HSRPv1 avec : support de 4096 groupes (0-4095 au lieu de 0-255), adresses MAC virtuelles etendues (0000.0c9f.fXXX), utilisation du multicast 224.0.0.102 (au lieu de 224.0.0.2), support d\'IPv6 et identification amelioree du routeur source dans les messages Hello.' },
  ],
  32: [
    { id: 'q32_1', question: 'Quelle est la difference entre une ACL standard et une ACL etendue ?', options: ['L\'ACL standard est plus securisee', 'L\'ACL standard filtre uniquement sur l\'adresse IP source, l\'ACL etendue filtre sur source, destination, protocole et port', 'L\'ACL etendue est uniquement pour IPv6', 'Il n\'y a aucune difference'], correct: 1, explanation: 'Une ACL standard (numerotee 1-99 ou 1300-1999) filtre uniquement sur l\'adresse IP source. Une ACL etendue (100-199 ou 2000-2699) filtre sur l\'adresse source, l\'adresse destination, le protocole (TCP, UDP, ICMP) et les numeros de port. Les ACL etendues sont plus granulaires et doivent etre placees au plus pres de la source du trafic.' },
    { id: 'q32_2', question: 'Que se passe-t-il si un paquet ne correspond a aucune entree dans une ACL ?', options: ['Le paquet est autorise par defaut', 'Le paquet est rejete par le "deny implicite" (implicit deny any) a la fin de chaque ACL', 'Le paquet est redirige', 'Le routeur demande a l\'administrateur'], correct: 1, explanation: 'Chaque ACL Cisco se termine par un "deny any" implicite (invisible dans la configuration). Si un paquet ne correspond a aucune regle explicite, il est automatiquement rejete. C\'est pourquoi il faut au moins une instruction "permit" dans chaque ACL, sinon tout le trafic est bloque. On peut ajouter "permit any" en fin d\'ACL si necessaire.' },
    { id: 'q32_3', question: 'Quel est le wildcard mask de 0.0.0.255 et a quoi correspond-il ?', options: ['Il correspond a un masque /32 (un seul hote)', 'Il correspond a un masque /24 (tout un reseau /24 — les 3 premiers octets doivent correspondre)', 'Il bloque toutes les adresses', 'Il correspond au masque 255.255.255.0'], correct: 1, explanation: 'Le wildcard mask 0.0.0.255 signifie que les 3 premiers octets doivent correspondre exactement (0 = verifier) et le dernier octet est ignore (255 = ignorer). C\'est l\'inverse du masque de sous-reseau 255.255.255.0 (/24). Pour un seul hote, le wildcard est 0.0.0.0. Pour toutes les adresses, c\'est 255.255.255.255.' },
    { id: 'q32_4', question: 'Ou doit-on placer une ACL standard par rapport au trafic ?', options: ['Le plus pres possible de la source du trafic', 'Le plus pres possible de la destination du trafic', 'Sur le switch d\'acces uniquement', 'Sur le pare-feu uniquement'], correct: 1, explanation: 'Les ACL standard filtrent uniquement sur l\'adresse source, donc si elles sont placees trop pres de la source, elles pourraient bloquer du trafic legitime vers d\'autres destinations. On les place le plus pres possible de la destination pour minimiser l\'impact. Les ACL etendues, plus precises, sont placees pres de la source pour economiser la bande passante.' },
    { id: 'q32_5', question: 'Quelle commande applique une ACL etendue sur une interface en direction entrante ?', options: ['access-list 100 in', 'ip access-group 100 in', 'ip access-list 100 inbound', 'apply acl 100 in'], correct: 1, explanation: 'La commande "ip access-group [numero-ACL] in" (ou "out") s\'applique en mode configuration d\'interface. "in" filtre le trafic entrant sur l\'interface et "out" filtre le trafic sortant. Une seule ACL peut etre appliquee par interface, par direction (une en in et une en out maximum). Le mot cle est "access-group" (pas "access-list") sur l\'interface.' },
    { id: 'q32_6', question: 'Quelle commande cree une ACL nommee etendue ?', options: ['access-list extended MONACL', 'ip access-list extended MONACL', 'named-acl extended MONACL', 'acl create MONACL extended'], correct: 1, explanation: 'La commande "ip access-list extended [NOM]" cree une ACL nommee etendue. Les ACL nommees sont plus lisibles et offrent l\'avantage de pouvoir supprimer ou inserer des lignes individuelles (sequence numbers) sans recreerl\'ACL entiere. Exemple : "ip access-list extended FILTRAGE_WEB" puis "permit tcp 192.168.1.0 0.0.0.255 any eq 443".' },
    { id: 'q32_7', question: 'Dans une ACL etendue, quelle commande autorise le trafic HTTP depuis le reseau 192.168.1.0/24 vers n\'importe quelle destination ?', options: ['permit ip 192.168.1.0 0.0.0.255 any', 'permit tcp 192.168.1.0 0.0.0.255 any eq 80', 'permit http 192.168.1.0 0.0.0.255 any', 'permit web 192.168.1.0 any any'], correct: 1, explanation: 'La syntaxe d\'une ACL etendue est : [permit|deny] [protocole] [source] [wildcard-source] [destination] [wildcard-dest] [eq port]. HTTP utilise TCP port 80, donc "permit tcp 192.168.1.0 0.0.0.255 any eq 80". Pour HTTPS, on utiliserait "eq 443". Le mot-cle "any" remplace "0.0.0.0 255.255.255.255".' },
    { id: 'q32_8', question: 'Quelle commande affiche les ACL configurees sur un routeur Cisco et le nombre de paquets correspondant a chaque regle ?', options: ['show running-config | include access-list', 'show access-lists', 'show ip access-group', 'show acl statistics'], correct: 1, explanation: 'La commande "show access-lists" affiche toutes les ACL avec leurs regles et le compteur de matches (nombre de paquets ayant correspondu a chaque regle). C\'est essentiel pour le troubleshooting : si un compteur ne s\'incremente pas, la regle ne correspond a aucun trafic. "show ip interface [interface]" montre quelle ACL est appliquee sur une interface.' },
    { id: 'q32_9', question: 'Quel mot-cle remplace l\'adresse 0.0.0.0 avec le wildcard 255.255.255.255 dans une ACL Cisco ?', options: ['all', 'any', 'everywhere', 'wildcard'], correct: 1, explanation: 'Le mot-cle "any" est un raccourci pour "0.0.0.0 255.255.255.255" et signifie "n\'importe quelle adresse IP". De meme, le mot-cle "host [adresse]" est un raccourci pour "[adresse] 0.0.0.0" (correspondance exacte sur un seul hote). Exemple : "permit tcp host 10.0.0.1 any eq 22" autorise SSH depuis l\'hote 10.0.0.1 vers toute destination.' },
    { id: 'q32_10', question: 'Combien d\'ACL maximum peut-on appliquer sur une interface de routeur Cisco (par direction) ?', options: ['Autant qu\'on veut', 'Une seule ACL par interface, par protocole (IPv4/IPv6), par direction (in/out)', 'Deux ACL par interface', 'Dix ACL par interface'], correct: 1, explanation: 'La regle est : une seule ACL par interface, par protocole, par direction. On peut donc avoir au maximum une ACL IPv4 in, une ACL IPv4 out, une ACL IPv6 in et une ACL IPv6 out sur la meme interface. Si on applique une nouvelle ACL, elle remplace l\'ancienne. Pour combiner des regles, il faut les mettre dans la meme ACL.' },
  ],
}
